module div_16bit(
    input [15:0] A, B,
    output reg [15:0] result, odd
);
    reg [15:0] a_reg, b_reg;
    integer i;

    always @* begin
        a_reg = A;
        b_reg = B;

        for(i = 0; i < 16; i = i + 1) begin
            if(a_reg[i * 2 + 1:i * 2] >= b_reg) begin
                result[i] = 1;
                a_reg[i * 2 + 1:i * 2] = a_reg[i * 2 + 1:i * 2] - b_reg;
            end else begin
                result[i] = 0;
            end

            if(i > 0) begin
                a_reg[i * 2 + 1:i * 2] = {a_reg[i * 2 + 1:i * 2], a_reg[i * 2]};
            end
        end

        odd = a_reg;
    end

endmodule
